.c { display: flex; margin-bottom: 6px; background: #e5e7eb; }
.jc-center  { justify-content: center; }
.jc-between { justify-content: space-between; }
.jc-evenly  { justify-content: space-evenly; }

.center-box {
  display: flex;
  justify-content: center;
  align-items: center;
  height: 120px;
  background: #ddd6fe;
}

.layout { display: flex; gap: 8px; }
.side { flex: 1; background: #fbbf24; padding: 10px; }
.main { flex: 2; background: #34d399; padding: 10px; }
